// Data for the widget reference: a grid index of cards (src/pages/.../widgets index)
// plus a detail page per widget (src/pages/docs/reference/widgets/[id].astro). Each
// `shot` matches a file in src/generated/shots (generated by the Mire.Shots tool).

export interface Param {
  name: string;
  type: string;
  desc: string;
}

export interface Related {
  href: string;
  label: string;
}

export interface Widget {
  id: string;
  title: string;
  summary: string;
  shot?: string; // filename (no extension) in src/generated/shots
  signature: string; // F#, multi-line
  params: Param[];
  details?: string; // a longer paragraph for the detail page
  example?: string; // F# usage snippet
  related?: Related[];
}

export interface Group {
  name: string;
  blurb: string;
  widgets: Widget[];
}

