// Flat, in-order list — for the grid, prev/next, and the [id] route.
export const ALL_WIDGETS: Widget[] = GROUPS.flatMap((g) => g.widgets);

export const widgetById = (id: string): Widget | undefined =>
  ALL_WIDGETS.find((w) => w.id === id);
